// ── Replay Export (Server) ──
// Writes replay artifacts to disk for static-site ingestion.

import { mkdir, writeFile } from "fs/promises";
import { join } from "path";
import type { ReplayManifest, ReplayPayload } from "@amc/core";

export interface WriteExportResult {
  slug: string;
  exportDir: string;
  manifestPath: string;
  payloadPath: string;
}

export async function writeReplayExport(
  manifest: ReplayManifest,
  payload: ReplayPayload,
  exportBaseDir: string,
): Promise<WriteExportResult> {
  const dir = join(exportBaseDir, manifest.slug);
  await mkdir(dir, { recursive: true });

  const manifestPath = join(dir, "manifest.json");
  const payloadPath = join(dir, "payload.json");

  await Promise.all([
    writeFile(manifestPath, JSON.stringify(manifest, null, 2), "utf-8"),
    writeFile(payloadPath, JSON.stringify(payload), "utf-8"),
  ]);

  return {
    slug: manifest.slug,
    exportDir: dir,
    manifestPath,
    payloadPath,
  };
}

