import { writeReplayExport } from "./replay-export.js";

const ACP_LOG_DIR = process.env.AMC_ACP_DIR || deriveACPLogDir(TARGET_WORKSPACE);
const EXPORT_DIR = process.env.AMC_EXPORT_DIR || join(TARGET_WORKSPACE, ".amc", "exports");

const MAX_EVENTS = 500;

// ── Replay export ──
app.post("/api/export", async (req, res) => {
  try {
    const { sessionId, projectName, youtubeUrl } = req.body as {
      sessionId?: string;
      projectName?: string;
      youtubeUrl?: string;
    };

    // Default to current session if no sessionId provided
    const targetSessionId = sessionId || state.sessionId;
    if (!targetSessionId || /[\/\\\.]{2}/.test(targetSessionId) || /[\/\\]/.test(targetSessionId)) {
      res.status(400).json({ error: "Invalid or missing session ID" });
      return;
    }

    // Parse events from the JSONL file
    const { createReadStream } = await import("fs");
    const { createInterface } = await import("readline");
    const { parseACPLine } = await import("@amc/core");

    const filePath = join(ACP_LOG_DIR, `${targetSessionId}.jsonl`);
    const stream = createReadStream(filePath, { encoding: "utf-8" });
    const rl = createInterface({ input: stream, crlfDelay: Infinity });
    const events: AMCEvent[] = [];

    for await (const line of rl) {
      const parsed = parseACPLine(line);
      events.push(...parsed);
    }

    if (events.length === 0) {
      res.status(400).json({ error: "Session has no events" });
      return;
    }

    // Build the export artifacts
    const { manifest, payload, slug } = buildReplayExport(events, {
      sessionId: targetSessionId,
      projectName: projectName || pathBasename(TARGET_WORKSPACE) || undefined,
      startedAt: state.startedAt,
      youtubeUrl,
    });

    // Write to disk
    const result = await writeReplayExport(manifest, payload, EXPORT_DIR);

    console.log(`[export] Exported session ${targetSessionId} → ${result.exportDir}`);
    res.json({
      ok: true,
      slug,
      exportDir: result.exportDir,
      manifestPath: result.manifestPath,
      payloadPath: result.payloadPath,
      eventCount: events.length,
      chapters: manifest.chapters.length,
      highlights: manifest.highlightCount,
    });
  } catch (err: any) {
    console.error(`[export] Error: ${err.message}`);
    res.status(500).json({ error: `Export failed: ${err.message}` });
  }
});

