app.get("/api/exports", async (_req, res) => {
  try {
    const { readdir, readFile } = await import("fs/promises");
    const entries = await readdir(EXPORT_DIR, { withFileTypes: true });
    const manifests = [];
    for (const entry of entries) {
      if (!entry.isDirectory()) continue;
      try {
        const raw = await readFile(join(EXPORT_DIR, entry.name, "manifest.json"), "utf-8");
        manifests.push(JSON.parse(raw));
      } catch {
        // skip dirs without valid manifests
      }
    }
    manifests.sort((a, b) => b.exportedAt.localeCompare(a.exportedAt));
    res.json({ exports: manifests });
  } catch {
    res.json({ exports: [] });
  }
});

