// ── Replay Export ──
// Produces self-contained replay artifacts for BilbroSwagginz.com.
// Multi-file pattern: one folder per session with separate files for
// metadata, events, transcript, and lessons.
//
// exports/replays/<slug>/
//   replay.json       — manifest + metadata (what the site needs for listing/detail pages)
//   events.json       — full event stream (replay player data)
//   transcript.json   — human-readable conversation transcript
//   lessons.json      — course, chapters, highlights, analytics

import type { AMCEvent } from "./events.js";
import type { RunCourse } from "./lessons.js";
import type { HighlightMoment } from "./highlights.js";
import type { RunAnalytics } from "./analytics.js";
import { generateRunCourse, generateYouTubeDescription } from "./lessons.js";
import { generateHighlightReel } from "./highlights.js";
import { computeAnalytics } from "./analytics.js";

// ── Types ──

export type ReplayStatus = "complete" | "partial" | "error";

export interface ReplaySource {
  tool: "claude-code";
  model?: string;
  amcVersion: string;
}

/** replay.json — the manifest BilbroSwagginz.com uses for archive/detail pages. */
export interface ReplayManifest {
  version: 1;
  slug: string;
  sessionId: string;
  exportedAt: string;

  // Display
  title: string;
  description: string;
  projectName: string;
  projectSlug?: string;
  date: string; // YYYY-MM-DD
  duration: string; // human-readable
  durationMs: number;

  // Classification
  tags: string[];
  status: ReplayStatus;
  source: ReplaySource;

  // Stats
  stats: {
    eventCount: number;
    commitCount: number;
    filesEdited: number;
    linesAdded: number;
    linesRemoved: number;
    toolCalls: number;
    estimatedCostUSD?: number;
  };

  // Concepts covered (for filtering/badges)
  conceptsCovered: string[];

  // Chapter markers (lightweight, no lesson bodies)
  chapters: Array<{
    id: string;
    title: string;
    icon: string;
    description: string;
    lessonCount: number;
    startIndex: number;
  }>;

  // Key moments (lightweight highlight pointers)
  keyMoments: Array<{
    label: string;
    icon: string;
    eventIndex: number;
    timestamp: string;
    score: number;
  }>;

  // Links
  youtubeUrl?: string;

  // File pointers (relative paths within the export folder)
  files: {
    events: "events.json";
    transcript: "transcript.json";
    lessons: "lessons.json";
  };
}

/** transcript.json — human-readable conversation log. */
export interface TranscriptEntry {
  role: "user" | "agent" | "tool" | "system";
  timestamp: string;
  text: string;
  toolName?: string;
  isError?: boolean;
}

export interface TranscriptFile {
  version: 1;
  sessionId: string;
  entries: TranscriptEntry[];
}

/** lessons.json — pre-computed educational content. */
export interface LessonsFile {
  version: 1;
  sessionId: string;
  course: RunCourse;
  highlights: HighlightMoment[];
  analytics: RunAnalytics;
  youtubeDescription: string;
  youtubeDescriptionShort: string;
}

/** events.json — raw event stream for the replay player. */
export interface EventsFile {
  version: 1;
  sessionId: string;
  eventCount: number;
  events: AMCEvent[];
}

/** The complete export result (all four files). */
export interface ReplayExportResult {
  slug: string;
  replay: ReplayManifest;
  events: EventsFile;
  transcript: TranscriptFile;
  lessons: LessonsFile;
}

// ── Slug generation ──

export function generateSlug(firstPrompt: string, sessionId: string): string {
  const suffix = sessionId.replace(/[^a-zA-Z0-9]/g, "").slice(-6);

  if (!firstPrompt || !firstPrompt.trim()) {
    return `session-${sessionId.replace(/[^a-zA-Z0-9]/g, "").slice(0, 8)}`;
  }

  const base = firstPrompt
    .toLowerCase()
    .slice(0, 60)
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/[\s-]+/g, "-")
    .replace(/^-+|-+$/g, "");

  return base ? `${base}-${suffix}` : `session-${suffix}`;
}

// ── Helpers ──

function extractFirstPrompt(events: AMCEvent[]): string {
  for (const e of events) {
    if (e.kind === "user_message" && e.text.trim()) {
      return e.text.trim();
    }
  }
  return "";
}

function extractModel(events: AMCEvent[]): string | undefined {
  for (const e of events) {
    if (e.kind === "agent_message" && e.model) {
      return e.model;
    }
  }
  return undefined;
}

function formatDuration(ms: number): string {
  const totalSeconds = Math.floor(ms / 1000);
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  if (hours > 0) return `${hours}h ${minutes}m`;
  if (minutes > 0) return `${minutes}m ${seconds}s`;
  return `${seconds}s`;
}

function titleFromPrompt(prompt: string): string {
  if (!prompt) return "Untitled Session";
  const firstSentence = prompt.split(/[.\n]/)[0].trim();
  if (firstSentence.length <= 80) return firstSentence;
  return firstSentence.slice(0, 77) + "...";
}

function slugifyProjectName(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/[\s-]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function deriveStatus(events: AMCEvent[]): ReplayStatus {
  // If last event is an error, mark as error
  const last = events[events.length - 1];
  if (last?.kind === "error") return "error";
  // If we have at least one commit, consider it complete
  if (events.some((e) => e.kind === "git_commit")) return "complete";
  // If we have significant activity, still complete
  if (events.length > 20) return "complete";
  return "partial";
}

function deriveTags(events: AMCEvent[], course: RunCourse): string[] {
  const tags = new Set<string>();

  // Add concept tags
  for (const c of course.summary.conceptsCovered) {
    tags.add(c.tag);
  }

  // Detect high-level tags from event patterns
  if (events.some((e) => e.kind === "agent_tool_use" && e.toolName === "Bash")) {
    tags.add("terminal");
  }
  if (events.some((e) => e.kind === "git_commit")) {
    tags.add("git");
  }
  const hasTests = events.some(
    (e) =>
      e.kind === "agent_tool_use" &&
      e.toolName === "Bash" &&
      /\b(test|jest|vitest|pytest)\b/i.test(String(e.input.command ?? "")),
  );
  if (hasTests) tags.add("testing");

  const hasErrors = events.some(
    (e) => e.kind === "agent_tool_result" && e.isError,
  );
  if (hasErrors) tags.add("debugging");

  return [...tags];
}

function buildTranscript(events: AMCEvent[]): TranscriptEntry[] {
  const entries: TranscriptEntry[] = [];

  for (const e of events) {
    switch (e.kind) {
      case "user_message":
        entries.push({
          role: "user",
          timestamp: e.timestamp,
          text: e.text,
        });
        break;

      case "agent_message":
        entries.push({
          role: "agent",
          timestamp: e.timestamp,
          text: e.text,
        });
        break;

      case "agent_tool_use":
        entries.push({
          role: "tool",
          timestamp: e.timestamp,
          text: summarizeToolUse(e.toolName, e.input),
          toolName: e.toolName,
        });
        break;

      case "agent_tool_result":
        if (e.isError) {
          entries.push({
            role: "tool",
            timestamp: e.timestamp,
            text: e.output.slice(0, 500),
            isError: true,
          });
        }
        break;

      case "git_commit":
        entries.push({
          role: "system",
          timestamp: e.timestamp,
          text: `Committed: ${e.message} (${e.filesChanged} files, +${e.insertions}/-${e.deletions})`,
        });
        break;
    }
  }

  return entries;
}

function summarizeToolUse(toolName: string, input: Record<string, unknown>): string {
  switch (toolName) {
    case "Read":
      return `Read ${input.file_path || input.path || "file"}`;
    case "Write":
      return `Write ${input.file_path || input.path || "file"}`;
    case "Edit":
      return `Edit ${input.file_path || input.path || "file"}`;
    case "Bash":
      return `Run: ${String(input.command ?? "").slice(0, 120)}`;
    case "Glob":
      return `Search files: ${input.pattern || ""}`;
    case "Grep":
      return `Search content: ${input.pattern || ""}`;
    default:
      return `${toolName}`;
  }
}

// ── Main export builder ──

export function buildReplayExport(
  events: AMCEvent[],
  metadata: {
    sessionId: string;
    projectName?: string;
    startedAt?: string | null;
    youtubeUrl?: string;
  },
): ReplayExportResult {
  const firstPrompt = extractFirstPrompt(events);
  const slug = generateSlug(firstPrompt, metadata.sessionId);

  // Derive end time from last event (not Date.now())
  const lastEvent = events[events.length - 1];
  const endedAt = lastEvent?.timestamp ?? null;

  // Compute all derived data
  const course = generateRunCourse(events, "beginner");
  const highlights = generateHighlightReel(events);
  const analytics = computeAnalytics(events, metadata.startedAt ?? null, endedAt);

  const youtubeDescription = generateYouTubeDescription(course, events, "full");
  const youtubeDescriptionShort = generateYouTubeDescription(course, events, "short");

  // Session date
  const sessionDate = metadata.startedAt ?? events[0]?.timestamp ?? new Date().toISOString();
  const date = sessionDate.slice(0, 10);

  const projectName = metadata.projectName || "unknown";
  const model = extractModel(events);

  // Count tool calls
  const toolCalls = events.filter((e) => e.kind === "agent_tool_use").length;

  // ── replay.json ──
  const replay: ReplayManifest = {
    version: 1,
    slug,
    sessionId: metadata.sessionId,
    exportedAt: new Date().toISOString(),

    title: titleFromPrompt(firstPrompt),
    description: course.summary.beginnerSummary || firstPrompt.slice(0, 200),
    projectName,
    projectSlug: slugifyProjectName(projectName),
    date,
    duration: formatDuration(analytics.runDurationMs),
    durationMs: analytics.runDurationMs,

    tags: deriveTags(events, course),
    status: deriveStatus(events),
    source: {
      tool: "claude-code",
      model,
      amcVersion: "0.1.0",
    },

    stats: {
      eventCount: events.length,
      commitCount: analytics.commitsMade,
      filesEdited: analytics.filesTouched,
      linesAdded: analytics.linesAdded,
      linesRemoved: analytics.linesRemoved,
      toolCalls,
      estimatedCostUSD: analytics.hasTokenData ? analytics.estimatedCostUSD : undefined,
    },

    conceptsCovered: course.summary.conceptsCovered.map((c) => c.tag),

    chapters: course.chapters.map((ch) => ({
      id: ch.id,
      title: ch.title,
      icon: ch.icon,
      description: ch.description,
      lessonCount: ch.lessons.length,
      startIndex: ch.startIndex,
    })),

    keyMoments: highlights.map((h) => ({
      label: h.label,
      icon: h.icon,
      eventIndex: h.eventIndex,
      timestamp: h.timestamp,
      score: h.score,
    })),

    youtubeUrl: metadata.youtubeUrl,

    files: {
      events: "events.json",
      transcript: "transcript.json",
      lessons: "lessons.json",
    },
  };

  // ── events.json ──
  const eventsFile: EventsFile = {
    version: 1,
    sessionId: metadata.sessionId,
    eventCount: events.length,
    events,
  };

  // ── transcript.json ──
  const transcriptFile: TranscriptFile = {
    version: 1,
    sessionId: metadata.sessionId,
    entries: buildTranscript(events),
  };

  // ── lessons.json ──
  const lessonsFile: LessonsFile = {
    version: 1,
    sessionId: metadata.sessionId,
    course,
    highlights,
    analytics,
    youtubeDescription,
    youtubeDescriptionShort,
  };

  return { slug, replay, events: eventsFile, transcript: transcriptFile, lessons: lessonsFile };
}

// ── Replay Export (Server) ──
// Writes replay artifacts to disk for static-site ingestion.
//
// Folder structure:
//   exports/replays/<slug>/
//     replay.json       — manifest + metadata
//     events.json       — full event stream
//     transcript.json   — human-readable conversation log
//     lessons.json      — course, chapters, highlights, analytics

import { mkdir, writeFile } from "fs/promises";
import { join } from "path";
import type {
  ReplayManifest,
  EventsFile,
  TranscriptFile,
  LessonsFile,
} from "@amc/core";

export interface WriteExportResult {
  slug: string;
  exportDir: string;
  files: {
    replay: string;
    events: string;
    transcript: string;
    lessons: string;
  };
}

export async function writeReplayExport(
  replay: ReplayManifest,
  events: EventsFile,
  transcript: TranscriptFile,
  lessons: LessonsFile,
  exportBaseDir: string,
): Promise<WriteExportResult> {
  const dir = join(exportBaseDir, replay.slug);
  await mkdir(dir, { recursive: true });

  const paths = {
    replay: join(dir, "replay.json"),
    events: join(dir, "events.json"),
    transcript: join(dir, "transcript.json"),
    lessons: join(dir, "lessons.json"),
  };

  await Promise.all([
    writeFile(paths.replay, JSON.stringify(replay, null, 2), "utf-8"),
    writeFile(paths.events, JSON.stringify(events), "utf-8"),
    writeFile(paths.transcript, JSON.stringify(transcript, null, 2), "utf-8"),
    writeFile(paths.lessons, JSON.stringify(lessons), "utf-8"),
  ]);

  return {
    slug: replay.slug,
    exportDir: dir,
    files: paths,
  };
}

